from __future__ import print_function, unicode_literals  # For Python 2/3 compatibility
import urllib.request
from selenium import webdriver

chrome = '/usr/bin/google-chrome' # Path to the chromedriver executable (Linux64)
chrome_options = webdriver.ChromeOptions()
chrome_options.binary_location = chrome
browser = webdriver.Chrome(chrome_options=chrome_options,executable_path=chrome)

def fetchImage(url):
    browser.get(url)  # Get the URL we want to scrape
    png = "/tmp/screenshot.png"
    browser.save_screenshot(png) # Take screenshot and save it as a PNG file locally
    return urllib.request.urlopen("file://"+png).read()

url = "http://www.python.org"  # You can replace this with the URL you want to take a screenshot of.
